import java.io.*;//////// a class used for reading numbers from the file.  this class is written in order to reduce the redundancy of the code	class ReadAFile extends FileInputStream{		public int end;				private String line = new String();				/*		*  @param	system recognized path of the file = (dir/filename) Ex.  Machintosh HD/Java/java.java		*		*/		public ReadAFile(String path) throws FileNotFoundException {			super(path);			end = 0;		}				public ReadAFile( String dir, String fileName) throws FileNotFoundException {			super(dir+fileName);			end = 0;		}				int readint()			throws IOException		 {			String msg = "";			int i;			do {				i = read();				if(i >= 48 & i<= 57)				msg += (char)i;			} while(  (i >=48 & i <= 57) | msg.length() == 0 );						end = i;					try {				if(msg != null)  {					i = Integer.parseInt(msg);					return( i );				}				else					return ( 0 );			}	catch(NumberFormatException e) {				System.out.println("NumberFormatException while reading an integer."+msg.length()+"-"+msg+"-");				return ( 0 );			}		}				float readfloat() 			throws IOException		{			String msg = "";			int i;						do {				i = read();								if(   (i >= 48 & i<= 57) | i  == 69 | i == 101 | i == 46) {     /////// if i is a number or E or e or .					if( i == 69 | i == 101) {					///////// if i == E or e						int temp = read();					//// read next character						if (temp == 43 | temp == 45) {			////  if next character is + or - then add both e/E and +/-							msg += (char)i;							msg += (char)temp;						}					}					else 						msg += (char)i;									}														} while(   !(i == -1 | i == 13 |   (msg.length() != 0 & (i ==32  |   i == 9)) ) );						end = i;										try {				if(msg != null)  {					return( Float.valueOf(msg).floatValue() );				}					else					return ( 0 );			}	catch(NumberFormatException e) {				System.out.println("NumberFormatException while reading a float value.");				return (0);			}		}				public String readLine() 				throws IOException		{				line = new String();			int i = 0;			do{				i = read();				if(i!= -1 & i!= 13)					line += (char) i;											} while( i!= -1 & i != 13);						end = i;						return line;		}				public String readFileLn() throws IOException{						readLine();						String file = new String();			boolean afterColon = false;			boolean afterSpaces = false;						int i=0;			char c;			do {				c = (char) line.charAt(i++);			} while(c != ':' );												for(int j=i; j< line.length(); j++) {				c = (char) line.charAt(j);								if( ((int)c != -1  && (int)c != 13  && (int)c != 9 ) )					if(  file.length() == 0 && (int) c == 32) ;					else 						file += c;											}						return file;					}						public String getLine() {			if( line != null)				return line;			else				return "";		}					}/////////////////////////    End of ReadANumber class	